def channel_stddev(raster: Raster) -> dict[str, float]:
    source = raster.to_rgb()
    means = channel_means(raster)
    pixel_count = len(source.data) // 3
    if pixel_count == 0:
        return {"red": 0.0, "green": 0.0, "blue": 0.0}
    totals = {"red": 0.0, "green": 0.0, "blue": 0.0}
    for index in range(0, len(source.data), 3):
        totals["red"] += (source.data[index] - means["red"]) ** 2
        totals["green"] += (source.data[index + 1] - means["green"]) ** 2
        totals["blue"] += (source.data[index + 2] - means["blue"]) ** 2
    return {
        channel: round(math.sqrt(total / pixel_count), 3)
        for channel, total in totals.items()
    }

