def sharpness_estimate(raster: Raster) -> float:
    source = raster.to_rgb()
    width = raster.width
    height = raster.height
    if width < 3 or height < 3:
        return 0.0
    total = 0.0
    count = 0
    for row in range(1, height - 1):
        for col in range(1, width - 1):
            index = (row * width + col) * 3
            for channel in range(3):
                center = source.data[index + channel]
                neighbors = (
                    source.data[index - 3 + channel],
                    source.data[index + 3 + channel],
                    source.data[index - width * 3 + channel],
                    source.data[index + width * 3 + channel],
                )
                laplacian = 4 * center - sum(neighbors)
                total += abs(laplacian)
                count += 1
    if count == 0:
        return 0.0
    return round(total / count, 3)

