def exposure_label(raster: Raster) -> str:
    values = luminance_values(raster)
    if not values:
        return "unknown"
    mean = sum(values) / len(values)
    if mean < 60:
        return "underexposed"
    if mean > 200:
        return "overexposed"
    if mean < 95:
        return "dark"
    if mean > 170:
        return "bright"
    return "balanced"
